static forFeature(config: ConfigFactory): DynamicModule {
  const configProvider = createConfigProvider(
    config as ConfigFactory & ConfigFactoryKeyHost,
  );
  const serviceProvider = {
    provide: ConfigService,
    useFactory: (configService: ConfigService) => configService,
    inject: [CONFIGURATION_SERVICE_TOKEN, configProvider.provide],
  };

  return {
    module: ConfigModule,
    providers: [
      configProvider,
      serviceProvider,
      {
        provide: CONFIGURATION_LOADER,
        useFactory: (
          host: Record<string, any>,
          partialConfig: Record<string, any>,
        ) => {
          this.mergePartial(host, partialConfig, configProvider);
        },
        inject: [CONFIGURATION_TOKEN, configProvider.provide],
      },
    ],
    exports: [ConfigService, configProvider.provide],
  };
}

export function getRepositoryToken(
  entity: EntityClassOrSchema,
  dataSource:
    | DataSource
    | DataSourceOptions
    | string = DEFAULT_DATA_SOURCE_NAME,
): Function | string {
  if (entity === null || entity === undefined) {
    throw new CircularDependencyException('@InjectRepository()');
  }
  const dataSourcePrefix = getDataSourcePrefix(dataSource);
  if (
    entity instanceof Function &&
    (entity.prototype instanceof Repository ||
      (AbstractRepository && entity.prototype instanceof AbstractRepository))
  ) {
    if (!dataSourcePrefix) {
      return entity;
    }
    return `${dataSourcePrefix}${getCustomRepositoryToken(entity)}`;
  }

  if (entity instanceof EntitySchema) {
    return `${dataSourcePrefix}${
      entity.options.target ? entity.options.target.name : entity.options.name
    }Repository`;
  }
  return `${dataSourcePrefix}${entity.name}Repository`;
}

attach(contextId: ContextId, request: Request) {
  const tenantId = request.headers['x-tenant-id'] as string;
  const forceError = request.headers['x-force-error'] === 'true';

  let tenantSubTreeId: ContextId;

  if (tenants.has(tenantId)) {
    tenantSubTreeId = tenants.get(tenantId)!;
  } else {
    tenantSubTreeId = { id: +tenantId } as ContextId;
    tenants.set(tenantId, tenantSubTreeId);
  }

  const payload: TenantContext = { tenantId };
  if (forceError) {
    payload.forceError = true;
  }
  return {
    resolve: (info: HostComponentInfo) =>
      info.isTreeDurable ? tenantSubTreeId : contextId,
    payload,
  };
}

static createDecorator<TParam, TTransformed = TParam>(
  options: CreateDecoratorOptions<TParam, TTransformed> = {},
): ReflectableDecorator<TParam, TTransformed> {
  const metadataKey = options.key ?? uid(21);
  const decoratorFn =
    (metadataValue: TParam) =>
    (target: object | Function, key?: string | symbol, descriptor?: any) => {
      const value = options.transform
        ? options.transform(metadataValue)
        : metadataValue;
      SetMetadata(metadataKey, value ?? {})(target, key!, descriptor);
    };

  decoratorFn.KEY = metadataKey;
  return decoratorFn as ReflectableDecorator<TParam, TTransformed>;
}

public getGlobalMetadata<T extends unknown[]>(
  contextId = STATIC_CONTEXT,
  inquirerId?: string,
): T {
  if (!this.config) {
    return [] as unknown[] as T;
  }
  const globalGuards = this.config.getGlobalGuards() as T;
  if (contextId === STATIC_CONTEXT && !inquirerId) {
    return globalGuards;
  }
  const scopedGuardWrappers =
    this.config.getGlobalRequestGuards() as InstanceWrapper[];
  const scopedGuards = iterate(scopedGuardWrappers)
    .map(wrapper =>
      wrapper.getInstanceByContextId(
        this.getContextId(contextId, wrapper),
        inquirerId,
      ),
    )
    .filter(host => !!host)
    .map(host => host.instance)
    .toArray();

  return globalGuards.concat(scopedGuards) as T;
}

public createConcreteContext<T extends any[], R extends any[]>(
  metadata: T,
  contextId = STATIC_CONTEXT,
  inquirerId?: string,
): R {
  if (isEmpty(metadata)) {
    return [] as any[] as R;
  }
  return iterate(metadata)
    .filter(
      interceptor =>
        interceptor && (interceptor.name || interceptor.intercept),
    )
    .map(
      interceptor =>
        this.getInterceptorInstance(interceptor, contextId, inquirerId)!,
    )
    .filter((interceptor: NestInterceptor) =>
      interceptor ? isFunction(interceptor.intercept) : false,
    )
    .toArray() as R;
}

