export class ModuleFinder {
  constructor(private tree: Tree) {}

  public find(options: FindOptions): Path | null {
    const generatedDirectoryPath: Path = options.path;
    const generatedDirectory: DirEntry = this.tree.getDir(
      generatedDirectoryPath,
    );
    return this.findIn(generatedDirectory);
  }

  private findIn(directory: DirEntry): Path | null {
    if (!directory) {
      return null;
    }
    const moduleFilename: PathFragment = directory.subfiles.find((filename) =>
      /\.module\.(t|j)s$/.test(filename),
    );
    return moduleFilename !== undefined
      ? join(directory.path, moduleFilename.valueOf())
      : this.findIn(directory.parent);
  }
}

constructor(
  @Optional()
  contextOrOptions?: string | ConsoleLoggerOptions,
  @Optional()
  options?: ConsoleLoggerOptions,
) {
  // eslint-disable-next-line prefer-const
  let [context, opts] = isString(contextOrOptions)
    ? [contextOrOptions, options]
    : options
      ? [undefined, options]
      : [contextOrOptions?.context, contextOrOptions];

  opts = opts ?? {};
  opts.logLevels ??= DEFAULT_LOG_LEVELS;
  opts.colors ??= opts.colors ?? (opts.json ? false : isColorAllowed());
  opts.prefix ??= 'Nest';

  this.options = opts;
  this.inspectOptions = this.getInspectOptions();

  if (context) {
    this.context = context;
    this.originalContext = context;
  }
}

protected printAsJson(
  message: unknown,
  options: {
    context: string;
    logLevel: LogLevel;
    writeStreamType?: 'stdout' | 'stderr';
    errorStack?: unknown;
  },
) {
  const logObject = this.getJsonLogObject(message, options);
  const formattedMessage =
    !this.options.colors && this.inspectOptions.compact === true
      ? JSON.stringify(logObject, this.stringifyReplacer)
      : inspect(logObject, this.inspectOptions);
  if (this.options.forceConsole) {
    if (options.writeStreamType === 'stderr') {
      console.error(formattedMessage);
    } else {
      console.log(formattedMessage);
    }
  } else {
    process[options.writeStreamType ?? 'stdout'].write(
      `${formattedMessage}\n`,
    );
  }
}

static overrideLogger(logger: LoggerService | LogLevel[] | boolean) {
  if (Array.isArray(logger)) {
    Logger.logLevels = logger;
    return this.staticInstanceRef?.setLogLevels?.(logger);
  }
  if (isObject(logger)) {
    if (logger instanceof Logger && logger.constructor !== Logger) {
      const errorMessage = `Using the "extends Logger" instruction is not allowed in Nest v9. Please, use "extends ConsoleLogger" instead.`;
      this.staticInstanceRef?.error(errorMessage);
      throw new Error(errorMessage);
    }
    this.staticInstanceRef = logger as LoggerService;
  } else {
    this.staticInstanceRef = undefined;
  }
}

buildErrorMessage(file?: IFile): string {
  const { errorMessage, message, ...config } = this.validationOptions;

  if (errorMessage) {
    return typeof errorMessage === 'function'
      ? errorMessage({ file, config })
      : errorMessage;
  }

  if (message) {
    return typeof message === 'function'
      ? message(this.validationOptions.maxSize)
      : message;
  }

  if (file?.size) {
    return `Validation failed (current file size is ${file.size}, expected size is less than ${this.validationOptions.maxSize})`;
  }
  return `Validation failed (expected size is less than ${this.validationOptions.maxSize})`;
}

protected toEmptyIfNil<T = any, R = T>(
  value: T,
  metatype: Type<unknown> | object,
): R | object | string {
  if (!isNil(value)) {
    return value as any as R;
  }
  if (
    typeof metatype === 'function' ||
    (metatype && 'prototype' in metatype && metatype.prototype?.constructor)
  ) {
    return {} as object;
  }
  // SWC requires empty string to be returned instead of an empty object
  // when the value is nil and the metatype is not a class instance, but a plain object (enum, for example).
  // Otherwise, the error will be thrown.
  // @see [https://github.com/nestjs/nest/issues/12680](https://github.com/nestjs/nest/issues/12680)
  return '';
}

protected mapChildrenToValidationErrors(
  error: ValidationError,
  parentPath?: string,
): ValidationError[] {
  if (!(error.children && error.children.length)) {
    return [error];
  }
  const validationErrors: ValidationError[] = [];
  parentPath = parentPath
    ? `${parentPath}.${error.property}`
    : error.property;
  for (const item of error.children) {
    if (item.children && item.children.length) {
      validationErrors.push(
        ...this.mapChildrenToValidationErrors(item, parentPath),
      );
    }
    validationErrors.push(
      this.prependConstraintsWithParentProp(parentPath, item),
    );
  }
  return validationErrors;
}

