protected stringifyMessage(message: unknown, logLevel: LogLevel) {
  if (isFunction(message)) {
    const messageAsStr = Function.prototype.toString.call(message);
    const isClass = messageAsStr.startsWith('class ');
    if (isClass) {
      // If the message is a class, we will display the class name.
      return this.stringifyMessage(message.name, logLevel);
    }
    // If the message is a non-class function, call it and re-resolve its value.
    return this.stringifyMessage(message(), logLevel);
  }

  if (typeof message === 'string') {
    return this.colorize(message, logLevel);
  }

  const outputText = inspect(message, this.inspectOptions);
  if (isPlainObject(message)) {
    return `Object(${Object.keys(message).length}) ${outputText}`;
  }
  if (Array.isArray(message)) {
    return `Array(${message.length}) ${outputText}`;
  }
  return outputText;
}

protected getContextAndStackAndMessagesToPrint(args: unknown[]) {
  if (args.length === 2) {
    return this.isStackFormat(args[1])
      ? {
          messages: [args[0]],
          stack: args[1] as string,
          context: this.context,
        }
      : { ...this.getContextAndMessagesToPrint(args) };
  }

  const { messages, context } = this.getContextAndMessagesToPrint(args);
  if (messages?.length <= 1) {
    return { messages, context };
  }
  const lastElement = messages[messages.length - 1];
  const isStack = isString(lastElement);
  // https://github.com/nestjs/nest/issues/11074#issuecomment-1421680060
  if (!isStack && !isUndefined(lastElement)) {
    return { messages, context };
  }
  return {
    stack: lastElement,
    messages: messages.slice(0, messages.length - 1),
    context,
  };
}

function printHelpAndExit(code: number): never {
  // Keep this simple so `npm run benchmarks` works without extra args.
  // Tuning: `--connections`, `--duration`, `--pipelining`, `--port`, `--path`
  // Notes: The benchmark spawns the framework server as a child process and
  // runs autocannon against it.
  //
  // eslint-disable-next-line no-console
  console.log(
    `
Usage:
  npm run benchmarks [-- --verbose]
  npm run benchmarks [-- --connections 100] [-- --duration 10] [-- --pipelining 10]
  npm run benchmarks [-- --port 3000] [-- --path /]

Defaults:
  verbose:   ${DEFAULTS.verbose}
  connections: ${DEFAULTS.connections}
  duration:    ${DEFAULTS.duration}
  pipelining:  ${DEFAULTS.pipelining}
  port:        ${DEFAULTS.port}
  path:        ${DEFAULTS.path}
`.trim(),
  );
  process.exit(code);
}

async update(updateSysConfigDto: UpdateSysConfigDto) {
  return await this.prisma.$transaction(async (prisma) => {
    const { configId, configKey } = updateSysConfigDto;
    const config = await prisma.sysConfig.findUnique({
      where: { configId },
    });
    if (!config) throw new ApiException('该记录不存在，请重新查询后操作。');
    const config2 = await prisma.sysConfig.findFirst({
      where: {
        configId: {
          not: configId,
        },
        configKey,
      },
    });
    if (config2) throw new ApiException('参数键名已存在，请更换后再试。');
    return await prisma.sysConfig.update({
      data: updateSysConfigDto,
      where: {
        configId,
      },
    });
  });
}

destination: async function (req, file, cd) {
  const currentDate = dayjs().format('YYYY-MM-DD');
  let path = '';
  if (uploadPath) {
    path = uploadPath + '/' + currentDate;
  } else {
    // 如果没有配置路径 就上传默认路径
    path = join(__dirname, `../../../../static/upload/${currentDate}`);
  }
  try {
    // 判断是否有该文件夹
    await fs.promises.stat(path);
  } catch (error) {
    // 没有该文件夹就创建
    await fs.promises.mkdir(path, { recursive: true });
  }
  // 挂载文件存储的路径
  if (uploadPath) {
    req.query.fileName = '/' + currentDate;
  } else {
    req.query.fileName = '/upload/' + currentDate;
  }
  cd(null, path);
}

