async insert(data: any, userName: string) {
  const userArr: User[] = []
  for await (const iterator of data) {
    let user = new User()
    if (!iterator.userName || !iterator.password || !iterator.nickName)
      throw new ApiException('用户账号、用户昵称、用户密码不能为空')
    const one = await this.findOneByUsername(iterator.userName)
    if (one) throw new ApiException('用户账号已存在，请检查')
    iterator.salt = await this.sharedService.generateUUID()
    iterator.password = this.sharedService.md5(iterator.password + iterator.salt)
    iterator.createBy = iterator.updateBy = userName
    const dept = await this.deptService.findById(1)
    iterator.dept = dept
    user = Object.assign(user, iterator)
    userArr.push(user)
  }
  await this.userRepository.createQueryBuilder().insert().into(User).values(userArr).execute()
}

async process(job: Job<SysJob>) {
  try {
    const { serviceName, funName, argumens } = await this.jobService.analysisinvokeTarget(job.data);
    const service = await this.moduleRef.get(this.jobService.ico[serviceName], { strict: false });
    if (job.data.concurrent == '0') {
      try {
        // 允许并发。  如果允许并发将无法捕获任务错误，任务全部为成功。
        service[funName](...argumens);
      } catch (error) {
        await this.logger.info(
          `可并发任务执行失败了,任务id:${job.id},任务名称:${job.name},任务数据:${JSON.stringify(job.data)}`,
        );
      }
    } else if (job.data.concurrent == '1') {
      //禁止并发
      await service[funName](...argumens);
    }
  } catch (error) {
    throw error;
  }
}

async addLoginInfor(request: Request, msg: string, status: string) {
  try {
    const addLoginInforDto = new AddLoginInforDto();
    const { username } = request.body;
    const { browser, os } = UAParser(request.headers['user-agent']); //获取用户电脑信息
    addLoginInforDto.userName = username;
    addLoginInforDto.ipaddr = this.sharedService.getReqIP(request);
    addLoginInforDto.loginLocation = await this.sharedService.getLocation(
      addLoginInforDto.ipaddr,
    );
    addLoginInforDto.status = status;
    addLoginInforDto.msg = msg;
    addLoginInforDto.loginTime = dayjs().format();
    addLoginInforDto.browser = browser.name + browser.version.split('.')[0];
    addLoginInforDto.os = os.name + os.version;
    await this.prisma.sysLoginInfor.create({ data: addLoginInforDto });
    return addLoginInforDto;
  } catch (error) {
    console.error('登录日志记录失败：' + error);
  }
}

async add(addSysDeptDto: AddSysDeptDto) {
  const { parentId } = addSysDeptDto;
  let parentDept = undefined;
  const dept = await this.prisma.$transaction(async (prisma) => {
    parentDept = await prisma.sysDept.findUnique({
      where: {
        deptId: parentId,
      },
    });
    if (!parentDept) throw new ApiException('上级部门不存在，请重新选择。');
    return await prisma.sysDept.create({
      data: addSysDeptDto,
    });
  });
  await this.prisma.sysDept.update({
    where: { deptId: dept.deptId },
    data: {
      ancestors: parentDept.ancestors + dept.deptId + ',',
    },
  });
}
